INSERT INTO services (slug, name, short_description, long_description, icon_name, base_price, rush_price, same_day_price, estimated_turnaround, sort_order, checklist_template, form_schema) VALUES
('process-serving','Process Serving','Professional process serving throughout Riverside County and Greater SoCal.','Our licensed process servers handle personal service, substituted service, and service by posting. All serves are documented with detailed affidavits that meet California CCP requirements.','FileText',8900,14900,22500,'1-5 business days standard, 24hrs rush, same-day expedited',1,'[{"label":"Review all documents from client","sort_order":1,"is_required":true},{"label":"Verify subject address","sort_order":2,"is_required":true},{"label":"Confirm court information","sort_order":3,"is_required":true},{"label":"Attempt 1 - Log date, time, address, outcome","sort_order":4,"is_required":true},{"label":"Attempt 2 - Log date, time, address, outcome","sort_order":5,"is_required":false},{"label":"Attempt 3 - Log date, time, address, outcome","sort_order":6,"is_required":false},{"label":"Complete CA Proof of Service form POS-010","sort_order":7,"is_required":true},{"label":"Upload signed Proof of Service","sort_order":8,"is_required":true},{"label":"Upload evidence photos if applicable","sort_order":9,"is_required":false},{"label":"Complete and upload Affidavit of Service","sort_order":10,"is_required":true},{"label":"Mark case as served and notify client","sort_order":11,"is_required":true}]'::jsonb,'{"fields":[{"name":"subject_name","label":"Subject Full Name","type":"text","required":true},{"name":"subject_address","label":"Subject Address","type":"text","required":true},{"name":"subject_city","label":"City","type":"text","required":true},{"name":"subject_state","label":"State","type":"text","default":"CA","required":true},{"name":"subject_zip","label":"ZIP Code","type":"text","required":true},{"name":"subject_phone","label":"Subject Phone","type":"tel","required":false},{"name":"court_case_number","label":"Court Case Number","type":"text","required":true},{"name":"court_name","label":"Court Name","type":"text","required":true},{"name":"plaintiff_name","label":"Plaintiff Name","type":"text","required":true},{"name":"defendant_name","label":"Defendant Name","type":"text","required":true},{"name":"documents_description","label":"Documents to be Served","type":"textarea","required":true},{"name":"special_instructions","label":"Special Instructions","type":"textarea","required":false}]}'::jsonb),
('notary','Notary Services','Certified mobile notary and loan signing agent services.','California Notary Public services including general notarizations, loan signings, apostilles, and after-hours services. Our mobile notary comes to you.','Stamp',9500,14500,19900,'Same day, Next day available',2,'[{"label":"Confirm appointment date, time, location","sort_order":1,"is_required":true},{"label":"Verify signer ID type","sort_order":2,"is_required":true},{"label":"Travel to appointment location","sort_order":4,"is_required":true},{"label":"Verify signer identity","sort_order":5,"is_required":true},{"label":"Complete notarization","sort_order":7,"is_required":true},{"label":"Record in notary journal","sort_order":8,"is_required":true},{"label":"Upload notarized document","sort_order":9,"is_required":true},{"label":"Confirm completion with client","sort_order":10,"is_required":true}]'::jsonb,'{"fields":[{"name":"doc_type","label":"Document Type","type":"select","required":true,"options":["Deed of Trust","Grant Deed","Power of Attorney","Trust Document","Affidavit","Loan Package","Other"]},{"name":"num_signatures","label":"Number of Signatures","type":"number","required":true},{"name":"appointment_location","label":"Signing Location","type":"text","required":true},{"name":"preferred_date","label":"Preferred Date","type":"date","required":true},{"name":"preferred_time","label":"Preferred Time","type":"time","required":true},{"name":"signer_name","label":"Signer Full Name","type":"text","required":true},{"name":"signer_phone","label":"Signer Phone","type":"tel","required":true},{"name":"special_instructions","label":"Special Instructions","type":"textarea","required":false}]}'::jsonb),
('skip-trace','Skip Trace','Locate individuals and assets using comprehensive database research.','Skip trace service locates subjects using proprietary databases, public records, and professional investigative networks. FCRA and DPPA compliant.','Search',7500,14900,NULL,'2-5 business days',3,'[{"label":"Review subject intake information","sort_order":1,"is_required":true},{"label":"Run basic database search","sort_order":2,"is_required":true},{"label":"Cross-reference records","sort_order":3,"is_required":true},{"label":"Search social media","sort_order":4,"is_required":false},{"label":"Compile skip trace report","sort_order":8,"is_required":true},{"label":"Upload final report","sort_order":10,"is_required":true},{"label":"Notify client of completion","sort_order":11,"is_required":true}]'::jsonb,'{"fields":[{"name":"subject_name","label":"Subject Full Name","type":"text","required":true},{"name":"subject_dob","label":"Date of Birth","type":"date","required":false},{"name":"subject_address","label":"Last Known Address","type":"text","required":false},{"name":"subject_phone","label":"Last Known Phone","type":"tel","required":false},{"name":"purpose","label":"Purpose","type":"select","required":true,"options":["Process Serving","Debt Collection","Child Support","Estate/Probate","Other Legal Matter"]},{"name":"tier","label":"Service Tier","type":"select","required":true,"options":["Basic ($75) - Address + Phone","Enhanced ($149) - Full Profile + Employer + Relatives"]},{"name":"special_instructions","label":"Additional Information","type":"textarea","required":false}]}'::jsonb),
('court-courier','Court Courier & Filing','Same-day court filing and document delivery.','Certified court couriers handle same-day filing at Riverside Superior Court, San Bernardino Superior Court, and other regional courts.','Truck',7500,15000,NULL,'Same day filing available',4,'[{"label":"Receive and review documents","sort_order":1,"is_required":true},{"label":"Verify court requirements","sort_order":2,"is_required":true},{"label":"Transport to courthouse","sort_order":4,"is_required":true},{"label":"File documents with clerk","sort_order":5,"is_required":true},{"label":"Obtain conformed copies","sort_order":6,"is_required":true},{"label":"Upload conformed copies and receipt","sort_order":9,"is_required":true},{"label":"Notify client of filing confirmation","sort_order":11,"is_required":true}]'::jsonb,'{"fields":[{"name":"court_name","label":"Court Name","type":"select","required":true,"options":["Riverside Superior Court - Main","Riverside Superior Court - Southwest","San Bernardino Superior Court","Orange County Superior Court","Los Angeles Superior Court","Other"]},{"name":"court_case_number","label":"Case Number","type":"text","required":true},{"name":"filing_type","label":"Filing Type","type":"select","required":true,"options":["Complaint","Motion","Response/Answer","Unlawful Detainer","Probate","Family Law","Small Claims","Other"]},{"name":"urgency","label":"Urgency","type":"select","required":true,"options":["Standard (same day)","Emergency (within 2 hours)"]},{"name":"special_instructions","label":"Special Instructions","type":"textarea","required":false}]}'::jsonb),
('legal-document-service','Legal Document Preparation','Professional legal document preparation for unlawful detainers, small claims, and family law.','Registered legal document assistants (LDA) prepare legal forms for self-represented litigants. We are not attorneys and do not provide legal advice.','FileEdit',9500,NULL,NULL,'1-3 business days',5,'[{"label":"Review client intake","sort_order":1,"is_required":true},{"label":"Identify correct Judicial Council forms","sort_order":2,"is_required":true},{"label":"Prepare draft documents","sort_order":4,"is_required":true},{"label":"Upload draft for client review","sort_order":6,"is_required":true},{"label":"Prepare final document set","sort_order":9,"is_required":true},{"label":"Upload final documents","sort_order":10,"is_required":true},{"label":"Notify client of completion","sort_order":12,"is_required":true}]'::jsonb,'{"fields":[{"name":"doc_type","label":"Document Type Needed","type":"select","required":true,"options":["Unlawful Detainer (Eviction)","Small Claims Complaint","Answer to Complaint","Name Change","Divorce Forms (Pro Per)","Child Support Modification","Fee Waiver (FW-001)","Proof of Service","Other"]},{"name":"case_description","label":"Brief Description","type":"textarea","required":true},{"name":"court_name","label":"Which Court?","type":"text","required":false},{"name":"deadline","label":"Filing Deadline?","type":"date","required":false},{"name":"special_instructions","label":"Additional Details","type":"textarea","required":false}]}'::jsonb);